INSERT INTO "Review" ("id", "userId", "name", "educationalInstitution", "rating", "text", "isPublished", "createdAt") VALUES
('cmp67i05q05gzlk9cfa2ga3gh', 'cmp66xi6y00d3lktgolbe56bh', 'Спиридонов Дьулустан Александрович', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-25, 1 курс', '3', 'Нормальный учебный трек: прошёл все модули, документ получил. Ни эйфории, ни разочарования — ровный рабочий материал для старта в теме безопасности.', 't', '2026-04-11 03:35:09.975'),
('cmp67i05p05gtlk9c3dy092jt', 'cmp66xi6q00culktgp4c4vxfb', 'Пендюр Роман Дмитриевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-25, 1 курс', '3', 'По специальности ОИБ материал зашёл: база закрыта, сертификат получил. Без пятерки — хотелось бы больше разборов «что делать, если уже попались» в бытовых сценариях.', 't', '2026-04-09 16:55:34.588'),
('cmp67i05p05gvlk9cv12qy68i', 'cmp66xi6u00cxlktgtzhise1p', 'Пестерев Иван Александрович', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-25, 1 курс', '2', 'Курс закончил, но тяжеловато по нагрузке параллельно с парой. Иногда не хватало пошаговых подсказок в практике. Итог: полезно, но не идеально.', 't', '2026-04-12 20:12:42.418'),
('cmp67i05q05gxlk9c6rtu8jx9', 'cmp66xi6w00d0lktgs79y80bu', 'Пьянков Артем Владимирович', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-25, 1 курс', '4', 'Хорошо стыкуется с очным расписанием: можно догнать дома. Сертификат получил. Минус — иногда неочевидно, где сохранился черновик практики.', 't', '2026-04-12 20:15:48.294'),
('cmp67i05r05h1lk9cq3pclj6r', 'cmp66xi7600d6lktgemqhfx5c', 'Старостин Николай Гаврильевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-25, 1 курс', '3', 'По специальности ОИБ материал зашёл: база закрыта, сертификат получил. Без пятерки — хотелось бы больше разборов «что делать, если уже попались» в бытовых сценариях.', 't', '2026-04-16 07:41:27.402'),
('cmp67i05r05h3lk9cazyv9z9g', 'cmp66xi7d00d9lktgjzwmbhu3', 'Федоров Владислав Геннадьевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-25, 1 курс', '5', 'Сильная практическая часть — после неё теория «ложится» в голову. Закрыл всё, сертификатом доволен. Рекомендую потоку.', 't', '2026-04-10 08:03:24.81'),
('cmp67i05s05h5lk9c0dyc2ke2', 'cmp5md5y90019gnc0mf4ek08u', 'Балаев Асман Яхьяевич', 'Якутский гуманитарный колледж, группа КИ-24, 3 курс', '5', 'Очень понравилось, что нельзя «прокликать» практику бездумно — проверка реально заставляет думать. Курс полностью прошёл, сертификатом доволен.', 't', '2026-04-07 10:54:36.124'),
('cmp67i05s05h7lk9cr6a91uhw', 'cmp66xidf00dclktgyypfevhd', 'Доржиева Нина Петровна', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-21, 5 курс', '3', 'Нормально для обязательного блока: база по ИБ закрыта, сертификат выдали. Без «вау», но претензий к честности курса нет.', 't', '2026-04-09 16:04:04.908'),
('cmp67i05t05h9lk9cww7rjf6s', 'cmp66xidk00dflktg67d62kc6', 'Николаев Александр Евгеньевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-21, 5 курс', '4', 'Хорошо легло на первый курс: не перегружает, но и не «детский сад». Сертификат получил. Звезду снял за пару формулировок в тестах.', 't', '2026-04-10 11:39:39.968'),
('cmp67i05t05hblk9c8bku51da', 'cmp66xidm00dilktg26w0blli', 'Попова Ирина Николаевна', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-21, 5 курс', '3', 'Ровный курс: прошла, сертификат на руках. Ни восторга, ни разочарования — как хороший учебник, только интерактивный.', 't', '2026-04-11 16:13:59.686'),
('cmp67i05t05hdlk9cnv24ae8l', 'cmp66xijo00dllktgtmj57zqt', 'Большаков Данил Васильевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-22, 4 курс', '5', 'Очень понятная траектория, не расползается «водой». Дошёл до конца быстрее, чем ожидал. Сертификат — плюс к мотивации дальше копать тему.', 't', '2026-04-13 11:31:02.085'),
('cmp67i05405eplk9cvxylvrs0', 'cmp5kx2ph000xgnzpumv5tfr9', 'Наумов Виталий Афанасьевич', 'Якутский гуманитарный колледж, группа КИ-25, 2 курс', '4', 'Курс прошёл до конца, сертификат забрал. Удобно, что всё в одном кабинете: лекция, тест, практика. Минус — иногда не хватало краткой шпаргалки в конце модуля.', 't', '2026-04-07 01:44:28.29'),
('cmp67i05505evlk9ci0kn1mzi', 'cmp65v9ce00a6lksam64ysu9q', 'Григорьев Марат', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-10 09:57:40.527'),
('cmp67i05v05hllk9c9uefbxxi', 'cmp66xik300dxlktgclwdesst', 'Куцев Денис Андреевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-22, 4 курс', '4', 'Прошёл курс до конца, материал связный. Практика с обратной связью — сильная сторона. Не идеально, но уверенная четвёрка.', 't', '2026-04-11 08:34:12.465'),
('cmp67i05v05hjlk9c2h0019j5', 'cmp66xijz00dulktg75exfdvw', 'Колесов Игнатий Иванович', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-22, 4 курс', '2', 'Курс в итоге закончил, но тянулось тяжело: местами слишком плотно по тексту, а обратная связь по практике шла не так быстро, как хотелось. На троечку тянет, не больше.', 't', '2026-04-14 00:58:08.311'),
('cmp67i05w05hnlk9c0ys0ri6r', 'cmp66xik600e0lktgnrmbxuhj', 'Ломсадзе Эрик Зурабович', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-22, 4 курс', '2', 'Дошёл до конца из-за зачёта. Полезные вещи есть, но подача местами сухая. Сертификат не компенсирует ощущение «протёрпел».', 't', '2026-04-14 09:10:10.822'),
('cmp67i05w05hplk9cceuzhd6r', 'cmp66xik800e3lktg69ml6dyi', 'Николаев Дмитрий Константинович', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-22, 4 курс', '5', 'Для заочного формата — очень достойно: и структура, и проверка практики. Закрыл все модули, сертификатом доволен, буду использовать в резюме.', 't', '2026-04-16 00:40:39.123'),
('cmp67i05x05hrlk9c54l0aoag', 'cmp5md5yl001cgnc077yydz4f', 'Бурцев Максим Юрьевич', 'Якутский гуманитарный колледж, группа КИ-24, 3 курс', '5', 'Отлично: и фишинг, и устройства, и сети — без перегруза. Закрыл всё, сертификат приятный бонус. Одногруппникам уже скинул ссылку.', 't', '2026-04-12 11:53:23.613'),
('cmp67i05y05htlk9cuqehp4l0', 'cmp66xikb00e6lktgvgffh6h4', 'Ощепков Дамир Валерьевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-22, 4 курс', '4', 'Прошёл курс до конца, материал связный. Практика с обратной связью — сильная сторона. Не идеально, но уверенная четвёрка.', 't', '2026-04-11 00:00:00.519'),
('cmp67i05y05hvlk9c2om9gjuf', 'cmp66xikd00e9lktggb0wdiym', 'Привалов Александр Дмитриевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-22, 4 курс', '2', 'Закончил курс, но местами было скучновато и много читать подряд. Практика спасает, но первые модули хотелось «поживее». На троечку с плюсом.', 't', '2026-04-16 03:42:45.244'),
('cmp67i05z05hxlk9cs5ndlvh1', 'cmp66xikf00eclktgjsgvcex4', 'Спиридонов Константин Владимирович', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-22, 4 курс', '2', 'Курс в итоге закончил, но тянулось тяжело: местами слишком плотно по тексту, а обратная связь по практике шла не так быстро, как хотелось. На троечку тянет, не больше.', 't', '2026-04-13 04:32:42.559'),
('cmp67i05z05hzlk9cpg5udpo7', 'cmp66xiki00eflktgv1ozgoyf', 'Шестаков Артур Петрович', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-9-22, 4 курс', '2', 'Курс в итоге закончил, но тянулось тяжело: местами слишком плотно по тексту, а обратная связь по практике шла не так быстро, как хотелось. На троечку тянет, не больше.', 't', '2026-04-09 16:58:15.486'),
('cmp67i06005i1lk9cxhpfinaw', 'cmp66xiqk00eilktgmqufdq53', 'Антоневич Артем Валерьевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '4', 'На третьем курсе как раз пригодился такой системный курс. Завершил полностью, сертификат приложу к портфолио. За минус — хотелось бы чуть больше видео, но текст хороший.', 't', '2026-04-12 15:13:30.276'),
('cmp67i06105i3lk9ck41wb3n3', 'cmp66xiqo00ellktgkgjnjug8', 'Архангельский Вячеслав Вячеславович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '4', 'Хорошо стыкуется с очным расписанием: можно догнать дома. Сертификат получил. Минус — иногда неочевидно, где сохранился черновик практики.', 't', '2026-04-10 03:38:02.397'),
('cmp67i06105i5lk9c948y6q1w', 'cmp66xiqr00eolktgzb7e0gqy', 'Борисов Айтал Артемович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '2', 'Курс в итоге закончил, но тянулось тяжело: местами слишком плотно по тексту, а обратная связь по практике шла не так быстро, как хотелось. На троечку тянет, не больше.', 't', '2026-04-10 13:26:19.02');